from outlines.prompts import register_filter, unregister_filter, Prompt
import outlines

register_filter('shout', str.upper)

@outlines.prompt
def greet(name):
    '''Hello {{ name | shout }}!'''

print(greet('world'))

unregister_filter('shout')

@outlines.prompt
def greet2(name):
    '''Hello {{ name | shout }}!'''

try:
    print(greet2('world'))
except Exception as e:
    print('Expected error after unregister:', type(e).__name__, e)
"

